command:example.dev:code:
Invoke-MgxRequest /users -All |
    Expand-MgxRelation -Uri '/users/{id}/manager' -As Manager -Flatten -SkipNotFound |
    Select-Object displayName, @{N='ManagerName'; E={$_.Manager.displayName}}

Invoke-MgxRequest /groups -All |
    Expand-MgxRelation -Uri '/groups/{id}/members' -As Members -Top 5 -SkipForbidden |
    Select-Object displayName, @{N='MemberCount'; E={$_.Members.Count}}

$requests = 1..100 | ForEach-Object {
    [PSCustomObject]@{
        Url = "/users"
        Method = "POST"
        Body = @{
            displayName = "User $_"
            mailNickname = "user$_"
            userPrincipalName = "user$_@contoso.com"
            accountEnabled = $true
            passwordProfile = @{ password = "P@ss$(Get-Random)!" }
        }
    }
}
$requests | Invoke-MgxBatchRequest

# Delete all decommissioned users in batches of 20
$users = Invoke-MgxRequest /users -Filter "department eq 'Decommissioned'" -All -Property id
$users | ForEach-Object { "/users/$($_.id)" } | Invoke-MgxBatchRequest -Method DELETE
# For large-scale deletes (1,000+), chunk and report progress:
# $urls = $users | ForEach-Object { "/users/$($_.id)" }
# for ($i = 0; $i -lt $urls.Count; $i += 1000) {
#     $urls[$i..([math]::Min($i+999, $urls.Count-1))] |
#         Invoke-MgxBatchRequest -Method DELETE -ErrorAction SilentlyContinue
# }

1..1000 | ForEach-Object {
    [PSCustomObject]@{ Url = "/users"; Method = "POST"; Body = @{ displayName = "User-$_"; mailNickname = "user$_"; userPrincipalName = "user$_@contoso.com"; passwordProfile = @{ password = "P@ss$(Get-Random -Minimum 10000)!" } } }
} | Invoke-MgxBatchRequest -DeadLetterPath ./failed-users.jsonl

# Correct: pipe all items into one call
$urls = 1..10000 | ForEach-Object { "/users/$_" }
$urls | Invoke-MgxBatchRequest

# Avoid: calling in a tight loop - slower and can cause threading errors at 200+ iterations
foreach ($url in $urls) { $url | Invoke-MgxBatchRequest }

Invoke-MgxRequest /users -Method POST -Body @{
    displayName = "New User"
    mailNickname = "newuser"
    userPrincipalName = "newuser@contoso.com"
    accountEnabled = $true
    passwordProfile = @{ password = "P@ssw0rd!" }
}

$search = Invoke-MgxRequest /security/auditLog/queries -Method POST -Body @{
    displayName         = "Last 24h sign-ins"
    filterStartDateTime = (Get-Date).AddDays(-1).ToString("o")
    filterEndDateTime   = (Get-Date).ToString("o")
    operationFilters    = @("userSignedIn")
}

# Poll until the search completes or fails (typically 5-15 minutes)
do {
    Start-Sleep -Seconds 10
    $status = Invoke-MgxRequest "/security/auditLog/queries/$($search.id)"
    if ($status.status -eq 'failed') { throw "Audit search failed" }
} while ($status.status -ne 'succeeded')

$records = Invoke-MgxRequest "/security/auditLog/queries/$($search.id)/records" -All

$sku = Invoke-MgxRequest /subscribedSkus | Where-Object skuPartNumber -eq 'ENTERPRISEPACK'
if (-not $sku) { throw "ENTERPRISEPACK SKU not found in tenant" }

Import-Csv ./users.csv |
    Select-Object -ExpandProperty UserPrincipalName |
    Invoke-MgxRequest '/users/{id}/assignLicense' -Method POST -Body @{
        addLicenses    = @(@{ skuId = $sku.skuId })
        removeLicenses = @()
    } -Concurrency 10

$results = Sync-MgxDelta /users/delta -DeltaPath C:\sync\users.delta -Property id,displayName,accountEnabled
$removed = $results | Where-Object { $_.'@removed' }
$changed = $results | Where-Object { -not $_.'@removed' }
Write-Host "$($changed.Count) changed, $($removed.Count) removed"
